@namespace Lumeo

@* Render the label, control and helper/error as ONE self-contained vertical block so the
   field never splays into a row when dropped in a flex / centered container. Standalone
   form-field structural fix. *@
<div class="@Cx.Merge("flex flex-col items-start", Cx.When(FullWidth, "w-full"))">
@if (Label is not null && !InsideFormField)
{
    <label class="text-sm font-medium leading-none">
        @Label
        @if (Required)
        {
            <span class="text-destructive ms-0.5">*</span>
        }
    </label>
}

@if (Variant == DatePickerVariant.Wheel)
{
    @* iOS-style 3-column wheel picker. v1 limitations:
       - Only honours single-date Mode (Range/Month/Year fall back to a day/month/year wheel).
       - No Presets sidebar.
       - ShowTimePicker is supported via a stacked TimeWheelPicker below the date wheel.
    *@
    @if (Inline)
    {
        <div>
            @* id/role/aria-describedby splat into AdditionalAttributes (DateWheelPicker has no matching
               [Parameter]s) so the FormField <Label For> resolves to a real element on this trigger-less
               variant too — the popover-trigger button gets the same EffectiveTriggerId (Codex P2). *@
            <DateWheelPicker Value="@Value" ValueChanged="HandleDateSelected" Min="@MinDate" Max="@MaxDate" Culture="@Culture"
                              id="@EffectiveTriggerId" role="group" aria-labelledby="@FormField?.LabelId" aria-describedby="@FormFieldDescribedBy" />
            @if (ShowTimePicker)
            {
                <div class="border-t border-border/40 p-3">
                    @* Detach the FormField cascade for the nested time-of-day picker: it is a sub-widget
                       of THIS DatePicker, not an independently field-associated control. Left cascaded,
                       it would ALSO compute the same FormFieldControlId as the date picker above and
                       render a DUPLICATE DOM id (Codex P2). *@
                    <CascadingValue Value="(FormField.FormFieldContext?)null" IsFixed="true">
                        <TimePicker Value="@Time" ValueChanged="HandleTimeChanged" Culture="@Culture" Variant="TimePicker.TimePickerVariant.Wheel" />
                    </CascadingValue>
                </div>
            }
        </div>
    }
    else
    {
        <Popover @bind-Open="_isOpen" Class="@(FullWidth ? "w-full" : null)">
            @* SuppressActivationKeys="true": this trigger's ChildContent is ALSO a native
               <button>, so without suppression an Enter/Space keydown bubbles to the
               wrapper's own HandleKeyDown AND the browser's own click synthesis for that
               same key ALSO bubbles up and toggles again via @onclick="Toggle" — two
               toggles cancel out and the wheel picker never opens from the keyboard.
               Mirrors the Calendar-variant button-trigger branch below (PR #356 round-6,
               Codex P2) — this Wheel-variant branch was missed by that fix (round-7,
               Codex P2). ChildContentSlot (instead of plain ChildContent) is required so
               aria-haspopup/aria-expanded/aria-controls land on the actual <button> —
               the real Tab stop once the wrapper's own tabindex drops to -1 — rather than
               only on the now-unfocusable wrapper (see PopoverTrigger's doc comment). *@
            <PopoverTrigger Class="@(FullWidth ? "w-full" : null)" SuppressActivationKeys="true">
                <ChildContentSlot Context="slot">
                <button type="button"
                        id="@EffectiveTriggerId"
                        name="@Name"
                        aria-required="@Required.ToString().ToLower()"
                        aria-invalid="@EffectiveInvalid.ToString().ToLower()"
                        aria-describedby="@FormFieldDescribedBy"
                        class="@CssClass"
                        disabled="@Disabled"
                        @attributes="MergeSlotAttributes(slot, EffectiveAttributes)">
                    <SvgGlyph Svg="@(LumeoIcons.Calendar)" class="me-2 h-4 w-4 shrink-0" />
                    @if (TriggerContent != null)
                    {
                        @TriggerContent
                    }
                    else if (Value.HasValue)
                    {
                        <span>@Value.Value.ToString(EffectiveFormat, EffectiveCulture)</span>
                    }
                    else
                    {
                        <span class="text-muted-foreground group-hover:text-accent-foreground">@EffectivePlaceholder</span>
                    }
                    @if (Clearable && HasValue)
                    {
                        <button type="button" class="ms-auto ps-1 hover:text-foreground focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-1 rounded" aria-label="@L["Common.Clear"]" @onclick="HandleClear" @onclick:stopPropagation="true">
                            <SvgGlyph Svg="@(LumeoIcons.X)" class="h-3.5 w-3.5" />
                        </button>
                    }
                </button>
                </ChildContentSlot>
            </PopoverTrigger>
            <PopoverContent Align="Lumeo.Align.Start" Class="w-[260px] p-3">
                <DateWheelPicker Value="@Value" ValueChanged="HandleDateSelected" Min="@MinDate" Max="@MaxDate" Culture="@Culture" />
                @if (ShowTimePicker)
                {
                    <div class="border-t border-border/40 mt-3 pt-3">
                        @* Detach the FormField cascade — see the Inline+Wheel branch's comment above
                           (Codex P2): a nested time-of-day TimePicker must not also claim the FormField's
                           ControlId, which is already on this Popover's trigger button. *@
                        <CascadingValue Value="(FormField.FormFieldContext?)null" IsFixed="true">
                            <TimePicker Value="@Time" ValueChanged="HandleTimeChanged" Culture="@Culture" Variant="TimePicker.TimePickerVariant.Wheel" />
                        </CascadingValue>
                    </div>
                }
            </PopoverContent>
        </Popover>
    }
}
else if (Inline)
{
        @* Every Calendar/DateWheelPicker below gets id/role/aria-describedby splatted into its
           AdditionalAttributes (neither declares matching [Parameter]s) so the FormField <Label For>
           resolves to a real rendered element here too — the popover-trigger button gets the same
           EffectiveTriggerId in the non-Inline branches (Codex P2). *@
        @if (Mode == DatePickerMode.Multiple)
        {
            <Calendar IsMultiple="true" Values="@Values" ValuesChanged="HandleValuesSelected" MinDate="@MinDate" MaxDate="@MaxDate" IsDateDisabled="@IsDateDisabled" DateClass="@DateClass" DateTooltip="@DateTooltip" DateBadge="@DateBadge" NumberOfMonths="@EffectiveNumberOfMonths" FirstDayOfWeek="@FirstDayOfWeek" ShowWeekNumbers="@ShowWeekNumbers" id="@EffectiveTriggerId" role="group" aria-labelledby="@FormField?.LabelId" aria-describedby="@FormFieldDescribedBy" />
        }
        else if (Mode == DatePickerMode.Month)
        {
            <Calendar Value="@Value" ValueChanged="HandleDateSelected" MinDate="@MinDate" MaxDate="@MaxDate" IsDateDisabled="@IsDateDisabled" DateClass="@DateClass" DateTooltip="@DateTooltip" DateBadge="@DateBadge" InitialView="@Calendar.CalendarView.Months" FirstDayOfWeek="@FirstDayOfWeek" ShowWeekNumbers="@ShowWeekNumbers" id="@EffectiveTriggerId" role="group" aria-labelledby="@FormField?.LabelId" aria-describedby="@FormFieldDescribedBy" />
        }
        else if (Mode == DatePickerMode.Year)
        {
            <Calendar Value="@Value" ValueChanged="HandleDateSelected" MinDate="@MinDate" MaxDate="@MaxDate" IsDateDisabled="@IsDateDisabled" DateClass="@DateClass" DateTooltip="@DateTooltip" DateBadge="@DateBadge" InitialView="@Calendar.CalendarView.Years" FirstDayOfWeek="@FirstDayOfWeek" ShowWeekNumbers="@ShowWeekNumbers" id="@EffectiveTriggerId" role="group" aria-labelledby="@FormField?.LabelId" aria-describedby="@FormFieldDescribedBy" />
        }
        else if (Mode == DatePickerMode.Range)
        {
            @if (Presets != null && Presets.Count > 0)
            {
                <div class="flex">
                    <div class="flex flex-col gap-1 border-e border-border/40 p-2 min-w-[120px]">
                        @foreach (var preset in Presets)
                        {
                            var p = preset;
                            <button type="button" class="text-sm px-3 py-1.5 rounded-md text-start hover:bg-accent hover:text-accent-foreground transition-colors focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-1" @onclick="() => HandlePresetSelected(p)">
                                @p.Label
                            </button>
                        }
                    </div>
                    <Calendar IsRange="true" RangeStart="@RangeStart" RangeStartChanged="HandleRangeStartChanged"
                              RangeEnd="@RangeEnd" RangeEndChanged="HandleRangeEndChanged"
                              MinDate="@MinDate" MaxDate="@MaxDate" IsDateDisabled="@IsDateDisabled" DateClass="@DateClass" DateTooltip="@DateTooltip" DateBadge="@DateBadge" NumberOfMonths="@EffectiveNumberOfMonths" FirstDayOfWeek="@FirstDayOfWeek" ShowWeekNumbers="@ShowWeekNumbers"
                              id="@EffectiveTriggerId" role="group" aria-labelledby="@FormField?.LabelId" aria-describedby="@FormFieldDescribedBy" />
                </div>
            }
            else
            {
                <Calendar IsRange="true" RangeStart="@RangeStart" RangeStartChanged="HandleRangeStartChanged"
                          RangeEnd="@RangeEnd" RangeEndChanged="HandleRangeEndChanged"
                          MinDate="@MinDate" MaxDate="@MaxDate" IsDateDisabled="@IsDateDisabled" DateClass="@DateClass" DateTooltip="@DateTooltip" DateBadge="@DateBadge" NumberOfMonths="@EffectiveNumberOfMonths" FirstDayOfWeek="@FirstDayOfWeek" ShowWeekNumbers="@ShowWeekNumbers"
                          id="@EffectiveTriggerId" role="group" aria-labelledby="@FormField?.LabelId" aria-describedby="@FormFieldDescribedBy" />
            }
        }
        else
        {
            <div>
                @if (Presets != null && Presets.Count > 0)
                {
                    <div class="flex">
                        <div class="flex flex-col gap-1 border-e border-border/40 p-2 min-w-[120px]">
                            @foreach (var preset in Presets)
                            {
                                var p = preset;
                                <button type="button" class="text-sm px-3 py-1.5 rounded-md text-start hover:bg-accent hover:text-accent-foreground transition-colors focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-1" @onclick="() => HandlePresetSelected(p)">
                                    @p.Label
                                </button>
                            }
                        </div>
                        <Calendar Value="@Value" ValueChanged="HandleDateSelected" MinDate="@MinDate" MaxDate="@MaxDate" IsDateDisabled="@IsDateDisabled" DateClass="@DateClass" DateTooltip="@DateTooltip" DateBadge="@DateBadge" NumberOfMonths="@EffectiveNumberOfMonths" FirstDayOfWeek="@FirstDayOfWeek" ShowWeekNumbers="@ShowWeekNumbers" id="@EffectiveTriggerId" role="group" aria-labelledby="@FormField?.LabelId" aria-describedby="@FormFieldDescribedBy" />
                    </div>
                }
                else
                {
                    <Calendar Value="@Value" ValueChanged="HandleDateSelected" MinDate="@MinDate" MaxDate="@MaxDate" IsDateDisabled="@IsDateDisabled" DateClass="@DateClass" DateTooltip="@DateTooltip" DateBadge="@DateBadge" NumberOfMonths="@EffectiveNumberOfMonths" FirstDayOfWeek="@FirstDayOfWeek" ShowWeekNumbers="@ShowWeekNumbers" id="@EffectiveTriggerId" role="group" aria-labelledby="@FormField?.LabelId" aria-describedby="@FormFieldDescribedBy" />
                }

                @if (ShowTimePicker)
                {
                    <div class="border-t border-border/40 p-3">
                        @* Detach the FormField cascade — see the Inline+Wheel branch's comment above
                           (Codex P2): a nested time-of-day TimePicker must not also claim the FormField's
                           ControlId, which is already on the Calendar above. *@
                        <CascadingValue Value="(FormField.FormFieldContext?)null" IsFixed="true">
                            <TimePicker Value="@Time" ValueChanged="HandleTimeChanged" Culture="@Culture" />
                        </CascadingValue>
                    </div>
                }
            </div>
        }
}
else
{
    <Popover @bind-Open="_isOpen" Class="@(FullWidth ? "w-full" : null)">
        @* SuppressActivationKeys is unconditional — BOTH branches below need it,
           for different reasons:
           - Typeable-input branch: the input already owns Enter (commit + close)
             and Space (a literal character) itself via HandleInputKeyDown — see
             PopoverTrigger's own doc comment on the parameter for why bubbling
             can't be fixed with stopPropagation alone (PR #356 round-2, Codex/
             CodeRabbit).
           - Button-trigger branch (the `else` below, range/multiple/custom-
             content modes): its ChildContent IS a native <button>. Without
             suppression here, an Enter/Space keydown on that button bubbles to
             this wrapper and toggles the popover via HandleKeyDown, and THEN the
             browser's own click synthesis for that same Enter/Space (native
             button default action) also bubbles up and toggles it again via
             @onclick="Toggle" — two toggles cancel out and the calendar never
             opens from the keyboard (PR #356 round-6, Codex P2). Suppressing
             here leaves only the single click-driven toggle, and — as a side
             effect — drops the wrapper's own tabindex to -1 so the native
             button (already its own tab stop) isn't ALSO a second one. *@
        <PopoverTrigger Class="@(FullWidth ? "w-full" : null)" SuppressActivationKeys="true">
            @* ChildContentSlot (instead of plain ChildContent) so PopoverTrigger can hand
               down aria-haspopup/aria-expanded/aria-controls for us to splat onto the
               actual focusable element in EACH branch below (the input, or the button) —
               SuppressActivationKeys already drops the wrapper's own tabindex to -1, so
               without this the popup relationship/expanded state would only ever live on
               that now-unfocusable wrapper (PR #356 round-7, Codex P2; see PopoverTrigger's
               doc comment on SuppressActivationKeys for the full mechanism). *@
            <ChildContentSlot Context="slot">
            @if (UsesTypeableInput)
            {
                @* No leading LumeoIcons.Calendar here — the trailing CalendarDays
                   button (below) already provides the visual + click target.
                   Rendering both produced a double calendar-icon affordance,
                   most visible on narrow mobile widths where the input shrinks. *@
                @* Clicking anywhere on the input BODY (the padded wrapper or the field
                   itself) opens the calendar — previously only the ~16px trailing icon
                   did (HandleInputClick). Both carry @onclick:stopPropagation so the open
                   never bubbles on to PopoverTrigger.Toggle (which would immediately close
                   it); the handler on each is required because the input's own
                   stopPropagation would otherwise keep a click on the field from reaching
                   the wrapper handler. *@
                <div class="@CssClass" @onclick="HandleInputClick" @onclick:stopPropagation="true" @attributes="AdditionalAttributes">
                    @* @onkeydown:stopPropagation is gated on _isOpen (the state as of the
                       LAST render, i.e. before this keystroke) rather than an unconditional
                       "true": while the calendar is open, containing every key (incl. Escape)
                       stops it from ALSO reaching an ancestor Dialog/Sheet's own Escape-to-
                       dismiss handler and closing that too — HandleInputKeyDown below already
                       closes the calendar on Escape, one press should only close the nearest
                       thing. Once the calendar is already closed, HandleInputKeyDown has
                       nothing left to do for Escape — stopping propagation then just swallows
                       it before that ancestor Dialog/Sheet can dismiss on it (Codex P2).
                       Enter/Space are handled separately: PopoverTrigger.SuppressActivationKeys
                       (set below) stops its role=button wrapper from treating either as a
                       toggle regardless of open/closed state — @onkeydown:stopPropagation being
                       a static per-render flag (not evaluated per key) can't do that alone
                       without also swallowing Escape (PR #356 round-2, Codex/CodeRabbit). *@
                    <input id="@EffectiveTriggerId"
                           type="text"
                           name="@Name"
                           value="@_inputBuffer"
                           placeholder="@EffectivePlaceholder"
                           aria-required="@Required.ToString().ToLower()"
                           aria-invalid="@EffectiveInvalid.ToString().ToLower()"
                           aria-describedby="@FormFieldDescribedBy"
                           disabled="@Disabled"
                           readonly="@(!AllowKeyboardInput)"
                           class="flex-1 min-w-0 bg-transparent outline-none border-0 p-0 text-sm placeholder:text-muted-foreground disabled:cursor-not-allowed"
                           @oninput="HandleInputChanged"
                           @onblur="HandleInputBlur"
                           @onkeydown="HandleInputKeyDown"
                           @onkeydown:stopPropagation="_isOpen"
                           @onclick="HandleInputClick"
                           @onclick:stopPropagation="true"
                           @attributes="slot.Attributes" />
                    @* This icon button is its OWN keyboard-focusable popup trigger — it opens/
                       closes the SAME popover as the input above via ToggleOpen — so it needs
                       the SAME slot.Attributes (aria-haspopup/aria-expanded/aria-controls) as
                       the input, not just the input alone. Without this, tabbing to the icon
                       button exposed a control with no popup relationship or expanded state to
                       screen-reader users (PR #356 round-9, Codex P2). aria-label stays static
                       and after slot.Attributes so it always wins over any future collision. *@
                    <button type="button"
                            class="ms-1 text-muted-foreground hover:text-foreground focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-1 rounded shrink-0"
                            disabled="@Disabled"
                            @onclick="ToggleOpen"
                            @onclick:stopPropagation="true"
                            @attributes="slot.Attributes"
                            aria-label="@L["DatePicker.OpenCalendar"]">
                        <SvgGlyph Svg="@(LumeoIcons.CalendarDays)" class="h-4 w-4" />
                    </button>
                    @if (Clearable && HasValue)
                    {
                        <button type="button" class="ms-1 hover:text-foreground focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-1 rounded shrink-0" aria-label="@L["Common.Clear"]" @onclick="HandleClear" @onclick:stopPropagation="true">
                            <SvgGlyph Svg="@(LumeoIcons.X)" class="h-3.5 w-3.5" />
                        </button>
                    }
                </div>
            }
            else
            {
            <button type="button"
                    id="@EffectiveTriggerId"
                    name="@Name"
                    aria-required="@Required.ToString().ToLower()"
                    aria-invalid="@EffectiveInvalid.ToString().ToLower()"
                    aria-describedby="@FormFieldDescribedBy"
                    class="@CssClass"
                    disabled="@Disabled"
                    @attributes="MergeSlotAttributes(slot, EffectiveAttributes)">
                <SvgGlyph Svg="@(LumeoIcons.Calendar)" class="me-2 h-4 w-4 shrink-0" />
                @if (TriggerContent != null)
                {
                    @TriggerContent
                }
                else if (Mode == DatePickerMode.Multiple)
                {
                    @if (Values is { Count: > 0 })
                    {
                        <span>@MultipleSummary</span>
                    }
                    else
                    {
                        <span class="text-muted-foreground group-hover:text-accent-foreground">@EffectivePlaceholder</span>
                    }
                }
                else if (Mode == DatePickerMode.Range)
                {
                    @if (RangeStart.HasValue && RangeEnd.HasValue)
                    {
                        <span>@RangeStart.Value.ToString(EffectiveFormat, EffectiveCulture) - @RangeEnd.Value.ToString(EffectiveFormat, EffectiveCulture)</span>
                    }
                    else if (RangeStart.HasValue)
                    {
                        <span>@RangeStart.Value.ToString(EffectiveFormat, EffectiveCulture) - ...</span>
                    }
                    else
                    {
                        <span class="text-muted-foreground group-hover:text-accent-foreground">@EffectivePlaceholder</span>
                    }
                }
                else if (Mode == DatePickerMode.Month)
                {
                    @if (Value.HasValue)
                    {
                        <span>@Value.Value.ToString("MMMM yyyy", EffectiveCulture)</span>
                    }
                    else
                    {
                        <span class="text-muted-foreground group-hover:text-accent-foreground">@EffectivePlaceholder</span>
                    }
                }
                else if (Mode == DatePickerMode.Year)
                {
                    @if (Value.HasValue)
                    {
                        <span>@Value.Value.Year</span>
                    }
                    else
                    {
                        <span class="text-muted-foreground group-hover:text-accent-foreground">@EffectivePlaceholder</span>
                    }
                }
                else
                {
                    @if (Value.HasValue)
                    {
                        <span>@Value.Value.ToString(EffectiveFormat, EffectiveCulture)</span>
                    }
                    else
                    {
                        <span class="text-muted-foreground group-hover:text-accent-foreground">@EffectivePlaceholder</span>
                    }
                }

                @if (Clearable && HasValue)
                {
                    <button type="button" class="ms-auto ps-1 hover:text-foreground focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-1 rounded" aria-label="@L["Common.Clear"]" @onclick="HandleClear" @onclick:stopPropagation="true">
                        <SvgGlyph Svg="@(LumeoIcons.X)" class="h-3.5 w-3.5" />
                    </button>
                }
            </button>
            }
            </ChildContentSlot>
        </PopoverTrigger>
        @* FocusOnOpen=false only for the typeable-input trigger so opening the calendar
           doesn't yank focus off the field mid-typing; the button trigger keeps the
           default focus-into-surface behaviour (Escape/keyboard land inside the dialog). *@
        <PopoverContent Align="Lumeo.Align.Start" Class="w-auto p-0" FocusOnOpen="@(!UsesTypeableInput)">
            @if (Mode == DatePickerMode.Multiple)
            {
                <Calendar IsMultiple="true" Values="@Values" ValuesChanged="HandleValuesSelected" MinDate="@MinDate" MaxDate="@MaxDate" IsDateDisabled="@IsDateDisabled" DateClass="@DateClass" DateTooltip="@DateTooltip" DateBadge="@DateBadge" NumberOfMonths="@EffectiveNumberOfMonths" FirstDayOfWeek="@FirstDayOfWeek" ShowWeekNumbers="@ShowWeekNumbers" />
            }
            else if (Mode == DatePickerMode.Month)
            {
                <Calendar Value="@Value" ValueChanged="HandleDateSelected" MinDate="@MinDate" MaxDate="@MaxDate" IsDateDisabled="@IsDateDisabled" DateClass="@DateClass" DateTooltip="@DateTooltip" DateBadge="@DateBadge" InitialView="@Calendar.CalendarView.Months" FirstDayOfWeek="@FirstDayOfWeek" ShowWeekNumbers="@ShowWeekNumbers" />
            }
            else if (Mode == DatePickerMode.Year)
            {
                <Calendar Value="@Value" ValueChanged="HandleDateSelected" MinDate="@MinDate" MaxDate="@MaxDate" IsDateDisabled="@IsDateDisabled" DateClass="@DateClass" DateTooltip="@DateTooltip" DateBadge="@DateBadge" InitialView="@Calendar.CalendarView.Years" FirstDayOfWeek="@FirstDayOfWeek" ShowWeekNumbers="@ShowWeekNumbers" />
            }
            else if (Mode == DatePickerMode.Range)
            {
                @if (Presets != null && Presets.Count > 0)
                {
                    <div class="flex">
                        <div class="flex flex-col gap-1 border-e border-border/40 p-2 min-w-[120px]">
                            @foreach (var preset in Presets)
                            {
                                var p = preset;
                                <button type="button" class="text-sm px-3 py-1.5 rounded-md text-start hover:bg-accent hover:text-accent-foreground transition-colors focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-1" @onclick="() => HandlePresetSelected(p)">
                                    @p.Label
                                </button>
                            }
                        </div>
                        <Calendar IsRange="true" RangeStart="@RangeStart" RangeStartChanged="HandleRangeStartChanged"
                                  RangeEnd="@RangeEnd" RangeEndChanged="HandleRangeEndChanged"
                                  MinDate="@MinDate" MaxDate="@MaxDate" IsDateDisabled="@IsDateDisabled" DateClass="@DateClass" DateTooltip="@DateTooltip" DateBadge="@DateBadge" NumberOfMonths="@EffectiveNumberOfMonths" FirstDayOfWeek="@FirstDayOfWeek" ShowWeekNumbers="@ShowWeekNumbers" />
                    </div>
                }
                else
                {
                    <Calendar IsRange="true" RangeStart="@RangeStart" RangeStartChanged="HandleRangeStartChanged"
                              RangeEnd="@RangeEnd" RangeEndChanged="HandleRangeEndChanged"
                              MinDate="@MinDate" MaxDate="@MaxDate" IsDateDisabled="@IsDateDisabled" DateClass="@DateClass" DateTooltip="@DateTooltip" DateBadge="@DateBadge" NumberOfMonths="@EffectiveNumberOfMonths" FirstDayOfWeek="@FirstDayOfWeek" ShowWeekNumbers="@ShowWeekNumbers" />
                }
            }
            else
            {
                <div>
                    @if (Presets != null && Presets.Count > 0)
                    {
                        <div class="flex">
                            <div class="flex flex-col gap-1 border-e border-border/40 p-2 min-w-[120px]">
                                @foreach (var preset in Presets)
                                {
                                    var p = preset;
                                    <button type="button" class="text-sm px-3 py-1.5 rounded-md text-start hover:bg-accent hover:text-accent-foreground transition-colors focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-1" @onclick="() => HandlePresetSelected(p)">
                                        @p.Label
                                    </button>
                                }
                            </div>
                            <Calendar Value="@Value" ValueChanged="HandleDateSelected" MinDate="@MinDate" MaxDate="@MaxDate" IsDateDisabled="@IsDateDisabled" DateClass="@DateClass" DateTooltip="@DateTooltip" DateBadge="@DateBadge" NumberOfMonths="@EffectiveNumberOfMonths" FirstDayOfWeek="@FirstDayOfWeek" ShowWeekNumbers="@ShowWeekNumbers" />
                        </div>
                    }
                    else
                    {
                        <Calendar Value="@Value" ValueChanged="HandleDateSelected" MinDate="@MinDate" MaxDate="@MaxDate" IsDateDisabled="@IsDateDisabled" DateClass="@DateClass" DateTooltip="@DateTooltip" DateBadge="@DateBadge" NumberOfMonths="@EffectiveNumberOfMonths" FirstDayOfWeek="@FirstDayOfWeek" ShowWeekNumbers="@ShowWeekNumbers" />
                    }

                    @if (ShowTimePicker)
                    {
                        <div class="border-t border-border/40 p-3">
                            @* Detach the FormField cascade — see the Inline+Wheel branch's comment above
                               (Codex P2): a nested time-of-day TimePicker must not also claim the
                               FormField's ControlId, which is already on this Popover's trigger button. *@
                            <CascadingValue Value="(FormField.FormFieldContext?)null" IsFixed="true">
                                <TimePicker Value="@Time" ValueChanged="HandleTimeChanged" Culture="@Culture" />
                            </CascadingValue>
                        </div>
                    }
                </div>
            }
        </PopoverContent>
    </Popover>
}

@if (!InsideFormField)
{
    @if (EffectiveInvalid && ErrorText is not null)
    {
        <p class="text-xs text-destructive">@ErrorText</p>
    }
    else if (HelperText is not null)
    {
        <p class="text-xs text-muted-foreground">@HelperText</p>
    }
}
</div>

@inject Lumeo.Services.Localization.ILumeoLocalizer L
@inject IComponentInteropService Interop

@code {
    public enum DatePickerMode { Single, Range, Month, Year, Multiple }

    /// <summary>
    /// Visual style of the picker.
    /// <see cref="DatePickerVariant.Calendar"/> renders the existing month-grid Calendar (default).
    /// <see cref="DatePickerVariant.Wheel"/> renders three iOS-style snap-scrolling
    /// columns (day / month / year) — designed for mobile / touch UIs.
    /// </summary>
    public enum DatePickerVariant { Calendar, Wheel }

    /// <summary>Picker visual style. Defaults to <see cref="DatePickerVariant.Calendar"/>.</summary>
    [Parameter] public DatePickerVariant Variant { get; set; } = DatePickerVariant.Calendar;

    [CascadingParameter] private FormField.FormFieldContext? FormField { get; set; }

    [Parameter] public bool Required { get; set; }
    [Parameter] public bool Invalid { get; set; }
    [Parameter] public string? ErrorText { get; set; }
    [Parameter] public string? HelperText { get; set; }
    [Parameter] public string? Label { get; set; }
    [Parameter] public string? Name { get; set; }

    private bool EffectiveInvalid => Invalid || FormField?.HasError == true;
    private bool InsideFormField => FormField is not null;

    // aria-describedby on the trigger announces the FormField help/error to a screen reader.
    private string? FormFieldDescribedBy => FormField?.DescribedBy;

    // Inside a FormField, adopt its generated ControlId so the field's <Label For>
