    // a FormField — EffectiveTriggerId then falls back to the generated _triggerId.
    // The empty guard avoids id="" when no id was generated.
    private string? FormFieldControlId => string.IsNullOrEmpty(FormField?.ControlId) ? null : FormField!.ControlId;

    // The id actually rendered on whichever trigger variant is active (button /
    // range button / masked input). Any interop that focuses or anchors the
    // trigger MUST use this same value so focus/anchoring target the rendered
    // element. _triggerId stays as the fallback.
    private string EffectiveTriggerId => FormFieldControlId ?? _triggerId;

    [Parameter] public DateOnly? Value { get; set; }
    [Parameter] public EventCallback<DateOnly?> ValueChanged { get; set; }

    /// <summary>
    /// Optional DateTime? binding. When set, takes precedence over <see cref="Value"/>.
    /// Changes fire both <see cref="ValueChanged"/> (DateOnly?) and <see cref="DateTimeValueChanged"/>
    /// (DateTime?). When <see cref="ShowTimePicker"/> is enabled the current <see cref="Time"/>
    /// selection is folded into the emitted DateTime; otherwise the time component is midnight.
    /// </summary>
    [Parameter] public DateTime? DateTimeValue { get; set; }
    [Parameter] public EventCallback<DateTime?> DateTimeValueChanged { get; set; }

    [Parameter] public string? Placeholder { get; set; }

    private string EffectivePlaceholder => Placeholder ?? (Mode == DatePickerMode.Range ? L["DateRange.Placeholder"] : L["DatePicker.Placeholder"]);
    /// <summary>
    /// Date format string. When null (default), the display falls back to the current
    /// culture's <c>ShortDatePattern</c> — so a <c>de-DE</c> user sees <c>15.03.2026</c>
    /// and an <c>en-US</c> user sees <c>3/15/2026</c> automatically.
    /// </summary>
    [Parameter] public string? Format { get; set; }

    /// <summary>
    /// Overrides <see cref="System.Globalization.CultureInfo.CurrentCulture"/> for
    /// parsing and formatting within this picker. Leave null to honour ASP.NET
    /// request localization.
    /// </summary>
    [Parameter] public System.Globalization.CultureInfo? Culture { get; set; }

    private System.Globalization.CultureInfo EffectiveCulture => Culture ?? System.Globalization.CultureInfo.CurrentCulture;
    private string EffectiveFormat => Format ?? EffectiveCulture.DateTimeFormat.ShortDatePattern;
    [Parameter] public DateOnly? MinDate { get; set; }
    [Parameter] public DateOnly? MaxDate { get; set; }
    /// <summary>Custom predicate to disable specific dates (e.g. booked rooms,
    /// unavailable slots). Returns <c>true</c> for dates that should not be
    /// selectable.</summary>
    [Parameter] public Func<DateTime, bool>? IsDateDisabled { get; set; }
    /// <summary>Custom CSS classes per day cell (e.g. status backgrounds for
    /// booking calendars).</summary>
    [Parameter] public Func<DateTime, string>? DateClass { get; set; }
    /// <summary>Per-date tooltip text rendered as the day cell's <c>title</c>
    /// attribute (native browser tooltip).</summary>
    [Parameter] public Func<DateTime, string?>? DateTooltip { get; set; }
    /// <summary>Per-date indicator slot (status dots, count badges, icons)
    /// rendered absolutely positioned in the bottom-right of the day cell.</summary>
    [Parameter] public Func<DateTime, RenderFragment?>? DateBadge { get; set; }
    [Parameter] public List<DatePickerPreset>? Presets { get; set; }
    [Parameter] public DatePickerMode Mode { get; set; } = DatePickerMode.Single;
    [Parameter] public DateOnly? RangeStart { get; set; }
    [Parameter] public EventCallback<DateOnly?> RangeStartChanged { get; set; }
    [Parameter] public DateOnly? RangeEnd { get; set; }
    [Parameter] public EventCallback<DateOnly?> RangeEndChanged { get; set; }

    /// <summary>The selected days for <see cref="DatePickerMode.Multiple"/>.
    /// Clicking a day (or Enter/Space on it) toggles it in/out of the set; the
    /// popover stays open so several days can be picked in one session. Pair
    /// with <see cref="ValuesChanged"/> for two-way binding.</summary>
    [Parameter] public List<DateOnly>? Values { get; set; }
    [Parameter] public EventCallback<List<DateOnly>?> ValuesChanged { get; set; }
    [Parameter] public bool ShowTimePicker { get; set; }
    [Parameter] public TimeSpan? Time { get; set; }
    [Parameter] public EventCallback<TimeSpan?> TimeChanged { get; set; }
    [Parameter] public bool Disabled { get; set; }
    [Parameter] public bool Clearable { get; set; }
    [Parameter] public RenderFragment? TriggerContent { get; set; }
    [Parameter] public int NumberOfMonths { get; set; } = 1;

    /// <summary>
    /// When true (default), the trigger renders as a typeable <c>&lt;input&gt;</c>
    /// in the configured <see cref="Format"/>. On blur / Enter the buffer is parsed
    /// via <see cref="DateOnly.TryParseExact(string, string, IFormatProvider, System.Globalization.DateTimeStyles, out DateOnly)"/>
    /// (with a fallback to <see cref="DateOnly.TryParse(string, IFormatProvider, System.Globalization.DateTimeStyles, out DateOnly)"/>).
    /// On success the value commits via <see cref="ValueChanged"/>; on failure the
    /// buffer reverts and <see cref="OnParseError"/> fires.
    /// Set to <c>false</c> to keep the historic button-only trigger (input readonly).
    /// Has no effect for <see cref="DatePickerMode.Range"/>, <see cref="DatePickerVariant.Wheel"/>,
    /// <see cref="Inline"/>, or when a custom <see cref="TriggerContent"/> is supplied.
    /// </summary>
    [Parameter] public bool AllowKeyboardInput { get; set; } = true;

    /// <summary>
    /// Fires when keyboard input cannot be parsed against the active <see cref="Format"/>
    /// (or culture short pattern), or parses to a date that is rejected by
    /// <see cref="MinDate"/>/<see cref="MaxDate"/>/<see cref="IsDateDisabled"/>.
    /// The argument is the offending raw buffer.
    /// </summary>
    [Parameter] public EventCallback<string> OnParseError { get; set; }

    private string _inputBuffer = string.Empty;
    private DateOnly? _lastSyncedValue;
    // CONTROLLED discriminator: the last Value we pushed to the parent via ValueChanged
    // (also updated whenever we adopt an authoritative incoming Value). Supports
    // controlled-rollback: if the parent re-renders with the SAME value we just pushed
    // it is merely an echo — skip re-syncing _inputBuffer; if it differs the parent
    // asserted a different value (normalization/rejection) and we adopt it.
    private DateOnly? _lastPushed;

    /// <summary>
    /// Optional controlled-mode override for the popover open state. When non-null,
    /// the consumer holds the source of truth — the picker no longer mutates its
    /// internal state and instead raises <see cref="OpenChanged"/>. Use this when
    /// the picker lives inside a parent that re-renders heavily (e.g. an
    /// <c>EditForm</c> with active <c>DataAnnotationsValidator</c>) and the
    /// popover would otherwise close mid-click during a parameter cascade.
    /// When null (default), the picker falls back to its internal open state and
    /// behaves exactly as before.
    /// </summary>
    /// <summary>When true, renders the calendar inline (always visible) without a popover wrapper.</summary>
    [Parameter] public bool Inline { get; set; }

    /// <summary>Leftmost column day of week. Null means culture default.</summary>
    [Parameter] public DayOfWeek? FirstDayOfWeek { get; set; }

    /// <summary>When true, renders an ISO week-number column.</summary>
    [Parameter] public bool ShowWeekNumbers { get; set; }

    [Parameter] public bool? Open { get; set; }

    /// <summary>
    /// Fires whenever the popover would open or close. Pair with
    /// <see cref="Open"/> via <c>@bind-Open</c> for the controlled-mode pattern
    /// described above.
    /// </summary>
    [Parameter] public EventCallback<bool> OpenChanged { get; set; }

    [Parameter] public string? Class { get; set; }
    /// <summary>
    /// When <c>true</c>, the date picker expands to fill its container width —
    /// equivalent to <c>FullWidth</c> on a <see cref="Button"/>. Propagates
    /// <c>w-full</c> to the Popover wrapper and PopoverTrigger so the constraint
    /// reaches the rendered trigger element through the shrink-wrap chain.
    /// </summary>
    [Parameter] public bool FullWidth { get; set; }
    /// <summary>Focuses the date-picker trigger on first render. Whichever
    /// trigger element is rendered (button / range-button / masked input)
    /// receives the focus via its shared id. See <c>Input.AutoFocus</c> for
    /// the rationale.</summary>
    [Parameter] public bool AutoFocus { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private readonly string _triggerId = LumeoIds.New("date-picker-trigger");

    /// <summary>Programmatically focus the trigger.</summary>
    public ValueTask FocusAsync() => Interop.FocusElement(EffectiveTriggerId);

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender && AutoFocus)
        {
            try { await Interop.FocusElement(EffectiveTriggerId); }
            catch (Microsoft.JSInterop.JSDisconnectedException) { }
        }
    }

    // Controlled-mode bridge: when Open is non-null, the parent owns the state and
    // we never write to _internalOpen — every "set" just raises OpenChanged so the
    // parent can decide. When Open is null, _internalOpen is the source of truth.
    private bool _internalOpen;
    private bool _isOpen
    {
        get => Open ?? _internalOpen;
        set => SetIsOpen(value);
    }

    private void SetIsOpen(bool value)
    {
        if (Open is null)
        {
            _internalOpen = value;
        }
        if (OpenChanged.HasDelegate)
        {
            // 2.2.3: was `_ = OpenChanged.InvokeAsync(value)` (fire-and-forget).
            // Wrap in InvokeAsync + try/catch so an exception in the consumer's
            // handler doesn't crash the circuit through an unobserved task.
            _ = InvokeAsync(async () =>
            {
                try { await OpenChanged.InvokeAsync(value); }
                catch { /* consumer-handler failure must not crash the popover */ }
            });
        }
    }

    private DateTime? _prevDateTimeValue;

    protected override void OnParametersSet()
    {
        // Keep the uncontrolled fallback (_internalOpen) mirrored to the
        // controlled Open while the parent owns the state. Without this, a
        // controlled close (Open toggled false by the parent) never updates the
        // stale _internalOpen, so a later revert to uncontrolled (Open => null)
        // would resurrect an old open state and reopen the popover unexpectedly.
        if (Open is { } controlledOpen)
        {
            _internalOpen = controlledOpen;
        }

        // DateTimeValue wins when it changes — sync Value from it.
        if (DateTimeValue != _prevDateTimeValue)
        {
            _prevDateTimeValue = DateTimeValue;
            Value = DateTimeValue.HasValue ? DateOnly.FromDateTime(DateTimeValue.Value) : null;
            // Also hydrate Time from the incoming DateTimeValue's time-of-day (ShowTimePicker
            // only — Time has no UI/meaning otherwise). Without this, RaiseDateTimeValueChanged
            // folds in the stale/null Time field (not what DateTimeValue actually carried), so
            // picking a new date after binding a non-midnight DateTimeValue silently reset the
            // committed time back to midnight (Codex P2).
            if (ShowTimePicker)
            {
                Time = DateTimeValue.HasValue ? DateTimeValue.Value.TimeOfDay : null;
            }
        }

        // Keep the typeable buffer in sync with Value whenever the parent pushes a new
        // bound value. The two branches implement the controlled/uncontrolled distinction:
        if (ValueChanged.HasDelegate)
        {
            // CONTROLLED: the parent owns Value and it is authoritative — EXCEPT when it
            // merely echoes back the exact value we just pushed (_lastPushed), where
            // adopting would disturb in-flight user text. Any OTHER incoming Value wins:
            // a normalisation, a programmatic reset, or a REJECTION that kept the old
            // value (crucial for controlled rollback — Codex P2).
            if (Value != _lastPushed)
            {
                _lastPushed = Value;
                _lastSyncedValue = Value;
                _inputBuffer = FormatBuffer(Value);
            }
        }
        else if (Value != _lastSyncedValue)
        {
            // UNCONTROLLED: component owns the live value; adopt only when the parent
            // genuinely changes the parameter — an unrelated re-render that re-supplies
            // the same stale Value must not clobber in-flight typed text.
            _lastSyncedValue = Value;
            _lastPushed = Value;
            _inputBuffer = FormatBuffer(Value);
        }
    }

    private string FormatBuffer(DateOnly? value)
    {
        if (!value.HasValue) return string.Empty;
        if (Mode == DatePickerMode.Month) return value.Value.ToString("MMMM yyyy", EffectiveCulture);
        if (Mode == DatePickerMode.Year) return value.Value.Year.ToString(EffectiveCulture);
        return value.Value.ToString(EffectiveFormat, EffectiveCulture);
    }

    private void HandleInputChanged(ChangeEventArgs e)
    {
        _inputBuffer = e.Value?.ToString() ?? string.Empty;
    }

    private async Task HandleInputBlur(FocusEventArgs _)
    {
        await CommitBufferAsync();
    }

    private async Task HandleInputKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
        {
            await CommitBufferAsync();
            _isOpen = false;
        }
        else if (e.Key == "Escape")
        {
            _inputBuffer = FormatBuffer(Value);
            _isOpen = false;
        }
    }

    private async Task CommitBufferAsync()
    {
        var buffer = _inputBuffer?.Trim() ?? string.Empty;

        if (buffer.Length == 0)
        {
            if (Value.HasValue)
            {
                Value = null;
                _lastSyncedValue = null;
                _lastPushed = null;
                await ValueChanged.InvokeAsync(null);
                await RaiseDateTimeValueChanged(null);
            }
            return;
        }

        if (TryParseBuffer(buffer, out var parsed))
        {
            if (IsDisallowedDate(parsed))
            {
                // The calendar grid silently refuses disabled / out-of-range days
                // (Calendar.IsDisabled) — typed input must reject them the same way.
                // Revert to the last valid value and surface the rejection through
                // OnParseError; never commit an invalid date through ValueChanged.
                _inputBuffer = FormatBuffer(Value);
                if (OnParseError.HasDelegate)
                {
                    await OnParseError.InvokeAsync(buffer);
                }
                return;
            }

            if (parsed != Value)
            {
                Value = parsed;
                _lastSyncedValue = parsed;
                _lastPushed = parsed;
                _inputBuffer = FormatBuffer(parsed);
                await ValueChanged.InvokeAsync(parsed);
                await RaiseDateTimeValueChanged(parsed);
            }
            else
            {
                // Normalise display even if value didn't change.
                _inputBuffer = FormatBuffer(parsed);
            }
        }
        else
        {
            // Revert to last good value and signal the error.
            _inputBuffer = FormatBuffer(Value);
            if (OnParseError.HasDelegate)
            {
                await OnParseError.InvokeAsync(buffer);
            }
        }
    }

    /// <summary>
    /// Mirrors the calendar grid's disabled-day predicate (<c>Calendar.IsDisabled</c>)
    /// so the typed-input path enforces the same constraints as day-cell clicks.
    /// </summary>
    private bool IsDisallowedDate(DateOnly date) =>
        (MinDate.HasValue && date < MinDate.Value) || (MaxDate.HasValue && date > MaxDate.Value)
        || (IsDateDisabled != null && IsDateDisabled(date.ToDateTime(TimeOnly.MinValue)));

    private bool TryParseBuffer(string buffer, out DateOnly result)
    {
        var culture = EffectiveCulture;
        var styles = System.Globalization.DateTimeStyles.None;

        if (Mode == DatePickerMode.Month)
        {
            if (DateTime.TryParseExact(buffer, new[] { "MMMM yyyy", "MMM yyyy", "yyyy-MM", "MM/yyyy" }, culture, styles, out var dt))
            {
                result = new DateOnly(dt.Year, dt.Month, 1);
                return true;
            }
        }
        else if (Mode == DatePickerMode.Year)
        {
            if (int.TryParse(buffer, System.Globalization.NumberStyles.Integer, culture, out var year) && year is >= 1 and <= 9999)
            {
                result = new DateOnly(year, 1, 1);
                return true;
            }
        }

        // Exact format first, then a lenient fallback.
        if (DateOnly.TryParseExact(buffer, EffectiveFormat, culture, styles, out result)) return true;
        if (DateOnly.TryParse(buffer, culture, styles, out result)) return true;
        return false;
    }

    private void ToggleOpen()
    {
        if (Disabled) return;
        _isOpen = !_isOpen;
    }

    // True exactly when the trigger renders as the typeable <input> (single/month/year,
    // keyboard input on, no custom TriggerContent). Drives both which branch renders and
    // PopoverContent.FocusOnOpen so the two never drift apart. The Wheel/Inline variants
    // are handled by earlier branches, so this is only consulted in the popover branch.
    private bool UsesTypeableInput =>
        AllowKeyboardInput && Mode != DatePickerMode.Range && Mode != DatePickerMode.Multiple && TriggerContent == null;

    // Body click on the typeable input trigger OPENS the calendar (idempotent — clicking
    // again while open must not close it, so the caret can be repositioned mid-edit). Kept
    // separate from the trailing icon's ToggleOpen, and paired with FocusOnOpen=false on the
    // popover surface so the input keeps focus and stays typeable while the calendar shows.
    private void HandleInputClick()
    {
        if (Disabled) return;
        if (!_isOpen) _isOpen = true;
    }

    private int EffectiveNumberOfMonths => NumberOfMonths > 1 ? NumberOfMonths : (Mode == DatePickerMode.Range ? 2 : 1);

    private bool HasValue => Mode switch
    {
        DatePickerMode.Range => RangeStart.HasValue,
        DatePickerMode.Multiple => Values is { Count: > 0 },
        _ => Value.HasValue
    };

    /// <summary>Trigger summary for multiple-selection: lists up to three dates
    /// in the active format, then collapses to a localized "N selected" count so
    /// the trigger never overflows.</summary>
    private string MultipleSummary
    {
        get
        {
            if (Values is not { Count: > 0 }) return string.Empty;
            if (Values.Count <= 3)
                return string.Join(", ", Values.OrderBy(d => d).Select(d => d.ToString(EffectiveFormat, EffectiveCulture)));
            return string.Format(EffectiveCulture, L["DatePicker.MultipleSelected"], Values.Count);
        }
    }

    private async Task HandleValuesSelected(List<DateOnly>? values)
    {
        Values = values;
        await ValuesChanged.InvokeAsync(values);
        // Multiple mode intentionally keeps the popover open so the user can
        // toggle several days in one session (like range's first click).
    }

    private string CssClass => Cx.Merge("group flex h-9 w-full items-center rounded-md border", (EffectiveInvalid ? "border-destructive ring-1 ring-destructive/20" : "border-input"), "bg-transparent px-3 py-2 text-sm shadow-sm hover:bg-accent hover:text-accent-foreground disabled:cursor-not-allowed disabled:opacity-50", Class);

    // Inside a FormField the EffectiveTriggerId must own the trigger element's id so
    // the <label for> and the rendered element always agree. A consumer-splatted id in
    // AdditionalAttributes would otherwise render after the generated id attribute and
    // silently win, causing the label's `for` to point at a missing element (Codex P2).
    // Strip the splatted id when inside a FormField; outside a FormField the consumer's
    // id passes through unchanged (EffectiveTriggerId falls back to the internal _triggerId).
    private Dictionary<string, object>? EffectiveAttributes =>
        InsideFormField && AdditionalAttributes?.ContainsKey("id") == true
            ? AdditionalAttributes.Where(kv => kv.Key != "id").ToDictionary(kv => kv.Key, kv => kv.Value)
            : AdditionalAttributes;

    // Merges a PopoverTrigger ChildContentSlot's aria-haspopup/aria-expanded/aria-controls
    // (see PopoverTrigger's SuppressActivationKeys doc comment) onto the SAME element that
    // also renders `extra` (EffectiveAttributes) — button-trigger branches splat both onto
    // one native <button>, so a single @attributes can only take one merged dictionary.
    // `extra` wins on key collision, mirroring PopoverTrigger.BuildAttrs's "author wins".
    private static Dictionary<string, object> MergeSlotAttributes(Lumeo.TriggerSlot slot, IReadOnlyDictionary<string, object>? extra)
    {
        var d = new Dictionary<string, object>(slot.Attributes);
        if (extra is not null)
            foreach (var kv in extra) d[kv.Key] = kv.Value;
        return d;
    }

    private async Task HandleDateSelected(DateOnly? date)
    {
        if (Mode == DatePickerMode.Month && date.HasValue)
        {
            Value = new DateOnly(date.Value.Year, date.Value.Month, 1);
            _lastPushed = Value;
            // Refresh the typed buffer to the picked value. Without this, a controlled
            // parent that echoes Value back hits the _lastPushed echo-skip in
            // OnParametersSet, leaving any in-flight draft text in the textbox (Codex P2).
            _inputBuffer = FormatBuffer(Value);
            await ValueChanged.InvokeAsync(Value);
            await RaiseDateTimeValueChanged(Value);
            _isOpen = false;
        }
        else if (Mode == DatePickerMode.Year && date.HasValue)
        {
            Value = new DateOnly(date.Value.Year, 1, 1);
            _lastPushed = Value;
            _inputBuffer = FormatBuffer(Value);
            await ValueChanged.InvokeAsync(Value);
            await RaiseDateTimeValueChanged(Value);
            _isOpen = false;
        }
        else
        {
            Value = date;
            _lastPushed = date;
            _inputBuffer = FormatBuffer(date);
            await ValueChanged.InvokeAsync(date);
            await RaiseDateTimeValueChanged(date);
            if (!ShowTimePicker)
            {
                _isOpen = false;
            }
        }
    }

    private async Task HandleRangeStartChanged(DateOnly? date)
    {
        RangeStart = date;
        await RangeStartChanged.InvokeAsync(date);
    }

    private async Task HandleRangeEndChanged(DateOnly? date)
    {
        RangeEnd = date;
        await RangeEndChanged.InvokeAsync(date);
        if (date.HasValue)
        {
            _isOpen = false;
        }
    }

    private async Task HandleTimeChanged(TimeSpan? time)
    {
        Time = time;
        await TimeChanged.InvokeAsync(time);
        // A time-only change must also flow into the DateTime binding — otherwise
        // ShowTimePicker time selection never reaches DateTimeValue. Re-compose
        // from the current Value (RaiseDateTimeValueChanged now folds in Time).
        await RaiseDateTimeValueChanged(Value);
    }

    private async Task HandlePresetSelected(DatePickerPreset preset)
    {
        if (Mode == DatePickerMode.Range)
        {
            // Range presets must drive the range pair, not Value — otherwise the
            // preset click just closes the popover without selecting anything.
            // A preset without an explicit End selects a single-day range.
            var start = preset.Date;
            var end = preset.End ?? preset.Date;
            if (end < start)
            {
                (start, end) = (end, start);
            }
            RangeStart = start;
            RangeEnd = end;
            await RangeStartChanged.InvokeAsync(start);
            await RangeEndChanged.InvokeAsync(end);
        }
        else
        {
            Value = preset.Date;
            _lastPushed = preset.Date;
            _inputBuffer = FormatBuffer(preset.Date);
            await ValueChanged.InvokeAsync(preset.Date);
            await RaiseDateTimeValueChanged(preset.Date);
        }
        _isOpen = false;
    }

    private async Task HandleClear()
    {
        if (Mode == DatePickerMode.Range)
        {
            RangeStart = null;
            RangeEnd = null;
            await RangeStartChanged.InvokeAsync(null);
            await RangeEndChanged.InvokeAsync(null);
        }
        else if (Mode == DatePickerMode.Multiple)
        {
            Values = null;
            await ValuesChanged.InvokeAsync(null);
        }
        else
        {
            Value = null;
            _lastPushed = null;
            _inputBuffer = FormatBuffer(null);
            await ValueChanged.InvokeAsync(null);
            await RaiseDateTimeValueChanged(null);
        }
        if (ShowTimePicker)
        {
            Time = null;
            await TimeChanged.InvokeAsync(null);
        }
    }

    private async Task RaiseDateTimeValueChanged(DateOnly? date)
    {
        if (DateTimeValueChanged.HasDelegate)
        {
            // Fold the current Time selection into the committed DateTime so a date
            // pick no longer silently resets the bound DateTime to midnight when a
            // time was already chosen (and so the time picker actually reaches the
            // DateTime binding). Falls back to midnight when no Time is set.
            var time = Time.HasValue ? TimeOnly.FromTimeSpan(Time.Value) : TimeOnly.MinValue;
            var dt = date.HasValue ? (DateTime?)date.Value.ToDateTime(time) : null;
            _prevDateTimeValue = dt;
            await DateTimeValueChanged.InvokeAsync(dt);
        }
    }

    /// <summary>
    /// Quick-select preset. For <see cref="DatePickerMode.Single"/> only
    /// <paramref name="Date"/> is used; for <see cref="DatePickerMode.Range"/>
    /// the preset selects <paramref name="Date"/>..<paramref name="End"/>
    /// (or a single-day range when <paramref name="End"/> is null).
    /// </summary>
    public record DatePickerPreset(string Label, DateOnly Date, DateOnly? End = null);
}

