    [Parameter] public Func<DateTime, string>? DateClass { get; set; }
    /// <summary>Per-date tooltip text rendered as the day cell's <c>title</c>.</summary>
    [Parameter] public Func<DateTime, string?>? DateTooltip { get; set; }
    /// <summary>Per-date indicator slot rendered absolutely positioned in the
    /// bottom-right of the day cell.</summary>
    [Parameter] public Func<DateTime, RenderFragment?>? DateBadge { get; set; }
    [Parameter] public string? Placeholder { get; set; }

    private string EffectivePlaceholder => Placeholder ?? L["DateRange.Placeholder"];
    /// <summary>
    /// Date format. When null (default) the inner <see cref="DatePicker"/> falls back
    /// to the effective culture's <c>ShortDatePattern</c> — so a <c>de-DE</c> user sees
    /// <c>15.03.2026</c> and an <c>en-US</c> user sees <c>3/15/2026</c> automatically.
    /// </summary>
    [Parameter] public string? Format { get; set; }
    [Parameter] public List<DateRangePreset>? Presets { get; set; }
    [Parameter] public bool Disabled { get; set; }
    [Parameter] public bool Clearable { get; set; } = true;
    /// <summary>
    /// When <c>true</c>, the date range picker expands to fill its container width.
    /// Forwarded directly to the inner <see cref="DatePicker"/>.
    /// </summary>
    [Parameter] public bool FullWidth { get; set; }
    [Parameter] public DayOfWeek? FirstDayOfWeek { get; set; }
    [Parameter] public bool ShowWeekNumbers { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private List<DatePicker.DatePickerPreset>? _datePickerPresets =>
        Presets?.Select(p => new DatePicker.DatePickerPreset(p.Label, p.Start, p.End)).ToList();

    public class DateRangePreset
    {
        public string Label { get; set; } = "";
        public DateOnly Start { get; set; }
        public DateOnly End { get; set; }
    }
}

@namespace Lumeo
@using System.Globalization
@using Lumeo.Internal
@implements IDisposable

<div class="@RootCssClass" @attributes="AdditionalAttributes" style="@RootStyle">
    @* Center selection indicator (overlays all columns) *@
    <div class="absolute start-0 end-0 top-1/2 -translate-y-1/2 h-10 border-y border-primary/30 pointer-events-none"></div>

    @* Day column *@
    <div class="flex-1 overflow-y-scroll snap-y snap-mandatory scrollbar-none h-full"
         @onscroll="OnDayScroll"
         @ref="_dayCol">
        <div class="h-[60px]"></div>
        @for (var d = 1; d <= _daysInMonth; d++)
        {
            var day = d;
            <div class="h-10 flex items-center justify-center snap-center text-base select-none @(day == _day ? "text-primary font-semibold" : "text-muted-foreground")">
                @day
            </div>
        }
        <div class="h-[60px]"></div>
    </div>

    @* Month column *@
    <div class="flex-1 overflow-y-scroll snap-y snap-mandatory scrollbar-none h-full"
         @onscroll="OnMonthScroll"
         @ref="_monthCol">
        <div class="h-[60px]"></div>
        @for (var m = 1; m <= 12; m++)
        {
            var month = m;
            var name = MonthLabel(month);
            <div class="h-10 flex items-center justify-center snap-center text-base select-none px-1 truncate @(month == _month ? "text-primary font-semibold" : "text-muted-foreground")">
                @name
            </div>
        }
        <div class="h-[60px]"></div>
    </div>

    @* Year column *@
    <div class="flex-1 overflow-y-scroll snap-y snap-mandatory scrollbar-none h-full"
         @onscroll="OnYearScroll"
         @ref="_yearCol">
        <div class="h-[60px]"></div>
        @foreach (var yr in _years)
        {
            var year = yr;
            <div class="h-10 flex items-center justify-center snap-center text-base select-none @(year == _year ? "text-primary font-semibold" : "text-muted-foreground")">
                @year
            </div>
        }
        <div class="h-[60px]"></div>
    </div>
</div>

@inject Lumeo.Services.IComponentInteropService Interop

@code {
    // --- Public API ----------------------------------------------------------
    [Parameter] public DateOnly? Value { get; set; }
    [Parameter] public EventCallback<DateOnly?> ValueChanged { get; set; }
    [Parameter] public DateOnly? Min { get; set; }
    [Parameter] public DateOnly? Max { get; set; }
    [Parameter] public CultureInfo? Culture { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    // --- Layout constants (must match markup) --------------------------------
    private const int ItemHeight = 40;   // h-10
    private const int Height = 160;      // overall column height

    // --- Element refs --------------------------------------------------------
    private ElementReference _dayCol;
    private ElementReference _monthCol;
    private ElementReference _yearCol;

    // --- Selection state -----------------------------------------------------
    private int _day = 1;
    private int _month = 1;
    private int _year = DateTime.Today.Year;
    private int _daysInMonth = 31;
    private List<int> _years = new();

    // Debounce state — one per column so a scroll on one column doesn't
    // cancel pending settle on another.
    private const int SnapDebounceMs = 100;
    private readonly DebouncedValue<int> _dayDebounced = new(SnapDebounceMs);
    private readonly DebouncedValue<int> _monthDebounced = new(SnapDebounceMs);
    private readonly DebouncedValue<int> _yearDebounced = new(SnapDebounceMs);
    private bool _initialised;
    // External-change resync: columns are scroll-positioned programmatically on
    // first render; when the bound Value changes from outside afterwards the
    // offsets go stale and the next user scroll commits from stale geometry.
    // Track the last value we synced (updated in RaiseChange so our own commits
    // echoed back by the parent don't count) and re-scroll when it changes.
    private DateOnly? _lastSyncedValue;
    private bool _resyncPending;
    // The year column's row set is rebuilt from Min/Max on every cascade. When
    // the bounds shift (even though Value is unchanged) the year list grows or
    // slides, so the previously-seeded scroll offset no longer centres the
    // selected year — track the last seen bounds and force a resync when they
    // move so OnAfterRenderAsync re-runs ScrollColumnsToSelectionAsync.
    private int? _lastMinYear;
    private int? _lastMaxYear;

    private CultureInfo EffectiveCulture => Culture ?? CultureInfo.CurrentCulture;

    private string RootCssClass => Cx.Merge("flex gap-2 relative", Class);
    private string RootStyle => $"height: {Height}px;";

    protected override void OnParametersSet()
    {
        if (Value != _lastSyncedValue)
        {
            _lastSyncedValue = Value;
            _resyncPending = true;
        }

        var seed = Value ?? DateOnly.FromDateTime(DateTime.Today);
        _day = seed.Day;
        _month = seed.Month;
        _year = seed.Year;

        var minYear = Min?.Year ?? DateTime.Today.Year - 50;
        var maxYear = Max?.Year ?? DateTime.Today.Year + 50;
        if (maxYear < minYear) maxYear = minYear;

        // A year-range change reshapes the year column geometry; the previously
        // seeded scroll offset becomes stale, so re-position on the next render.
        if (minYear != _lastMinYear || maxYear != _lastMaxYear)
        {
            _lastMinYear = minYear;
            _lastMaxYear = maxYear;
            _resyncPending = true;
        }

        _years = Enumerable.Range(minYear, maxYear - minYear + 1).ToList();
        _daysInMonth = DateTime.DaysInMonth(_year, _month);
        if (_day > _daysInMonth) _day = _daysInMonth;
    }

    private string MonthLabel(int month)
    {
        var names = EffectiveCulture.DateTimeFormat.AbbreviatedMonthNames;
        if (month - 1 < names.Length && !string.IsNullOrWhiteSpace(names[month - 1]))
        {
            return names[month - 1];
        }
        return month.ToString("D2");
    }

    // --- Scroll handlers -----------------------------------------------------
    private async Task OnDayScroll()
    {
        if (!_initialised) return; // ignore the programmatic OnAfterRender scroll
        var idx = await GetIndexAsync(_dayCol);
        if (idx < 0) return;
        var day = Math.Clamp(idx + 1, 1, _daysInMonth);
        _dayDebounced.Set(day);
    }

    private async Task OnMonthScroll()
    {
        if (!_initialised) return;
        var idx = await GetIndexAsync(_monthCol);
        if (idx < 0) return;
        var month = Math.Clamp(idx + 1, 1, 12);
        _monthDebounced.Set(month);
    }

    private async Task OnYearScroll()
    {
        if (!_initialised) return;
        var idx = await GetIndexAsync(_yearCol);
        if (idx < 0 || idx >= _years.Count) return;
        _yearDebounced.Set(_years[idx]);
    }

    private async Task<int> GetIndexAsync(ElementReference el)
    {
        var scrollTop = await Interop.WheelScrollTop(el);
        // Each item is `ItemHeight` tall; the first item sits 60px below the top
        // (top spacer). When item 0 is centered in the 160px viewport,
        // scrollTop = (60 + ItemHeight/2) - 160/2 = 60 + 20 - 80 = 0. So
        // index = round(scrollTop / ItemHeight).
        return (int)Math.Round(scrollTop / ItemHeight);
    }

    protected override void OnInitialized()
    {
        _dayDebounced.OnChanged(pending => InvokeAsync(async () =>
        {
            if (pending == _day) return;
            _day = pending;
            await RaiseChange();
            StateHasChanged();
        }));
        _monthDebounced.OnChanged(pending => InvokeAsync(async () =>
        {
            if (pending == _month) return;
            _month = pending;
            _daysInMonth = DateTime.DaysInMonth(_year, _month);
            if (_day > _daysInMonth) _day = _daysInMonth;
            await RaiseChange();
            StateHasChanged();
        }));
        _yearDebounced.OnChanged(pending => InvokeAsync(async () =>
        {
            if (pending == _year) return;
            _year = pending;
            _daysInMonth = DateTime.DaysInMonth(_year, _month);
            if (_day > _daysInMonth) _day = _daysInMonth;
            await RaiseChange();
            StateHasChanged();
        }));
    }

    private async Task RaiseChange()
    {
        try
        {
            var raw = new DateOnly(_year, _month, _day);
            var d = raw;
            if (Min.HasValue && d < Min.Value) d = Min.Value;
            if (Max.HasValue && d > Max.Value) d = Max.Value;
            // The user scrolled to an out-of-range value that we just clamped:
            // the columns are parked on `raw`, but the committed value is the
            // clamp. Force a re-scroll so the wheel snaps back to the clamped
            // selection instead of staying stranded on an out-of-range row.
            if (d != raw)
            {
                _resyncPending = true;
            }
            _year = d.Year; _month = d.Month; _day = d.Day;
            // Our own commit — when the parent echoes it back through the
            // Value parameter it is not an external change, so pre-mark it
            // as synced to avoid a redundant programmatic re-scroll.
            _lastSyncedValue = d;
            await ValueChanged.InvokeAsync(d);
        }
        catch (ArgumentOutOfRangeException)
        {
            // Defensive — DateOnly ctor guards against invalid combos. We already
            // re-clamp days on month/year change, so this branch is unreachable
            // under normal flow.
        }
    }

    // Test seam (state-on-data-change #55): drives a deterministic self-commit to
    // a specific day/month/year, mirroring what the debounced scroll handlers do
    // when the user settles each column. The real scroll path depends on JS
    // scroll offsets + a timer debounce that bUnit cannot reproduce; this runs
    // the same RaiseChange so the clamp-resync regression can be asserted.
    internal Task CommitSelectionForTest(int year, int month, int day)
    {
        _year = year;
        _month = month;
        _daysInMonth = DateTime.DaysInMonth(_year, _month);
        _day = Math.Clamp(day, 1, _daysInMonth);
        return RaiseChange();
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _resyncPending = false;
            await ScrollColumnsToSelectionAsync();
            // Defer enabling scroll handlers until after the programmatic
            // scrollTo writes have settled — otherwise the first @onscroll
            // would interpret the seed scroll as a user gesture.
            ScheduleScrollHandlerEnable();
        }
        else if (_resyncPending)
        {
            // The bound Value changed externally — re-position the columns so
            // the visible offsets match the new selection. Suppress the scroll
            // handlers while the programmatic scrolls run (same reasoning as
            // the first-render seeding), then re-enable once settled.
            _resyncPending = false;
            _initialised = false;
            await ScrollColumnsToSelectionAsync();
            ScheduleScrollHandlerEnable();
        }
    }

    private async Task ScrollColumnsToSelectionAsync()
    {
        await Interop.WheelScrollTo(_dayCol, (_day - 1) * ItemHeight);
        await Interop.WheelScrollTo(_monthCol, (_month - 1) * ItemHeight);
        var yearIdx = _years.IndexOf(_year);
        if (yearIdx >= 0)
        {
            await Interop.WheelScrollTo(_yearCol, yearIdx * ItemHeight);
        }
    }

    // 2.2.3: was Task.Delay().ContinueWith(...) which runs the
    // continuation on the thread pool and swallows any exception
    // unobserved. InvokeAsync(async () => { delay; flip flag; })
    // keeps the work on the Blazor sync context and surfaces
    // failures through the normal renderer error path.
    private void ScheduleScrollHandlerEnable()
    {
        _ = InvokeAsync(async () =>
        {
            try
            {
                await Task.Delay(150);
                _initialised = true;
            }
            catch (JSDisconnectedException) { /* circuit teardown — fine */ }
        });
    }

    public void Dispose()
    {
        _dayDebounced.Dispose();
        _monthDebounced.Dispose();
        _yearDebounced.Dispose();
    }
}
